        dx = 1
    elif sx > target_x:
        dx = -1
    dy = 0
    if sy < target_y:
        dy = 1
    elif sy > target_y:
        dy = -1

    # try to move toward center if legal; otherwise stay or adjust away from obstacle
    if legal(sx + dx, sy + dy):
        return [dx, dy]

    # try other adjacent cells in a deterministic order
    for ddx, ddy in dirs:
        nx, ny = sx + ddx, sy + ddy
        if legal(nx, ny):
            return [ddx, ddy]

    # stay if no legal move
    return [0, 0]
